        docData = docData.substring(1); // Remove BOM
        charsetName = defaultCharset;
        doc = parser.parseInput(docData, baseUri); // Parse again after removing BOM
    }

    if (doc != null) {
        doc.outputSettings().charset(charsetName); // Set output charset
    }

    return doc;
}
```

